@app.route('/users', methods=['GET'])
def list_users():
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    role = request.args.get('role')
    is_active = request.args.get('is_active')
    
    query = {}
    if role:
        query['role'] = role
    if is_active is not None:
        query['is_active'] = is_active.lower() == 'true'
    
    skip = (page - 1) * limit
    
    users = list(users_collection.find(query).skip(skip).limit(limit).sort('created_at', DESCENDING))
    total = users_collection.count_documents(query)
    
    return jsonify({
        'users': [serialize_doc(user) for user in users],
        'total': total,
        'page': page,
        'limit': limit,
        'pages': (total + limit - 1) // limit
    }), 200


@app.route('/documents', methods=['POST'])
def create_document():
    data = request.get_json()
    
    required_fields = ['title', 'content', 'author_id']
    if not all(field in data for field in required_fields):
        return jsonify({'error': 'Missing required fields'}), 400
    
    try:
        author = users_collection.find_one({'_id': ObjectId(data['author_id'])})
        if not author:
            return jsonify({'error': 'Author not found'}), 404
    except Exception as e:
        return jsonify({'error': 'Invalid author_id'}), 400
    
    document = {
        'title': data['title'],
        'content': data['content'],
        'author_id': ObjectId(data['author_id']),
        'author_name': author['full_name'],
        'status': data.get('status', 'draft'),
        'tags': data.get('tags', []),
        'category': data.get('category', ''),
        'views': 0,
        'likes': 0,
        'comments_count': 0,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': datetime.utcnow() if data.get('status') == 'published' else None,
        'metadata': data.get('metadata', {}),
        'attachments': data.get('attachments', [])
    }
    
    try:
        result = documents_collection.insert_one(document)
        document['_id'] = str(result.inserted_id)
        return jsonify({'message': 'Document created successfully', 'document': serialize_doc(document)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 400


