@app.route('/documents/<document_id>', methods=['PUT'])
def update_document(document_id):
    data = request.get_json()
    
    update_fields = {}
    allowed_fields = ['title', 'content', 'status', 'tags', 'category', 'metadata', 'attachments']
    
    for field in allowed_fields:
        if field in data:
            update_fields[field] = data[field]
    
    if not update_fields:
        return jsonify({'error': 'No valid fields to update'}), 400
    
    update_fields['updated_at'] = datetime.utcnow()
    
    if 'status' in data and data['status'] == 'published':
        document = documents_collection.find_one({'_id': ObjectId(document_id)})
        if document and not document.get('published_at'):
            update_fields['published_at'] = datetime.utcnow()
    
    try:
        result = documents_collection.update_one(
            {'_id': ObjectId(document_id)},
            {'$set': update_fields}
        )
        
        if result.matched_count:
            document = documents_collection.find_one({'_id': ObjectId(document_id)})
            return jsonify({'message': 'Document updated successfully', 'document': serialize_doc(document)}), 200
        return jsonify({'error': 'Document not found'}), 404
    except Exception as e:
        return jsonify({'error': str(e)}), 400


