@app.route('/documents', methods=['GET'])
def list_documents():
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    status = request.args.get('status')
    author_id = request.args.get('author_id')
    category = request.args.get('category')
    tag = request.args.get('tag')
    search = request.args.get('search')
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = request.args.get('sort_order', 'desc')
    
    query = {}
    
    if status:
        query['status'] = status
    
    if author_id:
        try:
            query['author_id'] = ObjectId(author_id)
        except:
            return jsonify({'error': 'Invalid author_id'}), 400
    
    if category:
        query['category'] = category
    
    if tag:
        query['tags'] = tag
    
    if search:
        query['$or'] = [
            {'title': {'$regex': search, '$options': 'i'}},
            {'content': {'$regex': search, '$options': 'i'}}
        ]
    
    skip = (page - 1) * limit
    sort_direction = DESCENDING if sort_order == 'desc' else ASCENDING
    
    documents = list(documents_collection.find(query).skip(skip).limit(limit).sort(sort_by, sort_direction))
    total = documents_collection.count_documents(query)
    
    return jsonify({
        'documents': [serialize_doc(doc) for doc in documents],
        'total': total,
        'page': page,
        'limit': limit,
        'pages': (total + limit - 1) // limit
    }), 200


