@app.route('/analytics/trending-documents', methods=['GET'])
def trending_documents():
    days = int(request.args.get('days', 7))
    limit = int(request.args.get('limit', 10))
    
    from_date = datetime.utcnow()
    from datetime import timedelta
    from_date = from_date - timedelta(days=days)
    
    pipeline = [
        {
            '$match': {
                'created_at': {'$gte': from_date},
                'status': 'published'
            }
        },
        {
            '$addFields': {
                'engagement_score': {
                    '$add': [
                        {'$multiply': ['$views', 1]},
                        {'$multiply': ['$likes', 5]},
                        {'$multiply': ['$comments_count', 10]}
                    ]
                }
            }
        },
        {
            '$sort': {'engagement_score': -1}
        },
        {
            '$limit': limit
        },
        {
            '$project': {
                'title': 1,
                'author_name': 1,
                'views': 1,
                'likes': 1,
                'comments_count': 1,
                'engagement_score': 1,
                'created_at': 1,
                'category': 1,
                'tags': 1
            }
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    
    return jsonify({'trending_documents': [serialize_doc(doc) for doc in results]}), 200


@app.route('/analytics/user-activity', methods=['GET'])
def user_activity():
    pipeline = [
        {
            '$group': {
                '_id': '$role',
                'total_users': {'$sum': 1},
                'active_users': {
                    '$sum': {'$cond': ['$is_active', 1, 0]}
                }
            }
        }
    ]
    
    user_stats = list(users_collection.aggregate(pipeline))
    
    document_pipeline = [
        {
            '$lookup': {
                'from': 'users',
                'localField': 'author_id',
                'foreignField': '_id',
                'as': 'author_info'
            }
        },
        {
            '$unwind': '$author_info'
        },
        {
            '$group': {
                '_id': '$author_info.role',
                'total_documents': {'$sum': 1},
                'avg_views': {'$avg': '$views'},
                'avg_likes': {'$avg': '$likes'}
            }
        }
    ]
    
    document_stats = list(documents_collection.aggregate(document_pipeline))
    
    return jsonify({
        'user_statistics': user_stats,
        'document_statistics': document_stats
    }), 200


@app.route('/analytics/monthly-activity', methods=['GET'])
def monthly_activity():
    months = int(request.args.get('months', 6))
    
    pipeline = [
        {
            '$group': {
                '_id': {
                    'year': {'$year': '$created_at'},
                    'month': {'$month': '$created_at'}
                },
                'total_documents': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                }
            }
        },
        {
            '$sort': {'_id.year': -1, '_id.month': -1}
        },
        {
            '$limit': months
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    
    return jsonify({'monthly_activity': results}), 200


def serialize_doc(doc):
    if doc is None:
        return None
    doc_copy = dict(doc)
    if '_id' in doc_copy:
        doc_copy['_id'] = str(doc_copy['_id'])
    if 'author_id' in doc_copy:
        doc_copy['author_id'] = str(doc_copy['author_id'])
    if 'created_at' in doc_copy and isinstance(doc_copy['created_at'], datetime):
        doc_copy['created_at'] = doc_copy['created_at'].isoformat()
    if 'updated_at' in doc_copy and isinstance(doc_copy['updated_at'], datetime):
        doc_copy['updated_at'] = doc_copy['updated_at'].isoformat()
    if 'published_at' in doc_copy and isinstance(doc_copy['published_at'], datetime):
        doc_copy['published_at'] = doc_copy['published_at'].isoformat()
    return doc_copy


